function validateScript(scriptSource) {
  if (!scriptSource || typeof scriptSource !== 'string') {
    return { valid: false, reason: 'Script source must be a non-empty string' };
  }

  if (scriptSource.length > 2000) {
    return { valid: false, reason: 'Script source exceeds maximum length of 2000 characters' };
  }

  for (const pattern of FORBIDDEN_PATTERNS) {
    if (pattern.test(scriptSource)) {
      return { valid: false, reason: `Script contains forbidden pattern: ${pattern}` };
    }
  }

  return { valid: true };
}

