function buildBaseQuery(queryParams) {
  const { query } = queryParams;

  if (query.bool) {
    return { bool: query.bool };
  }

  if (query.match) {
    return { match: query.match };
  }

  if (query.multi_match) {
    return { multi_match: query.multi_match };
  }

  if (query.term) {
    return { term: query.term };
  }

  if (query.terms) {
    return { terms: query.terms };
  }

  if (query.range) {
    return { range: query.range };
  }

  if (query.exists) {
    return { exists: query.exists };
  }

  if (query.wildcard) {
    return { wildcard: query.wildcard };
  }

  if (query.prefix) {
    return { prefix: query.prefix };
  }

  if (query.fuzzy) {
    return { fuzzy: query.fuzzy };
  }

  if (query.match_phrase) {
    return { match_phrase: query.match_phrase };
  }

  if (query.query_string) {
    return { query_string: query.query_string };
  }

  if (query.nested) {
    return { nested: query.nested };
  }

  if (query.match_all) {
    return { match_all: query.match_all };
  }

  return { match_all: {} };
}

function buildFilters(filters) {
  if (!filters || filters.length === 0) return [];

  return filters.map((filter) => {
    switch (filter.type) {
      case 'term':
        return { term: { [filter.field]: filter.value } };
      case 'terms':
        return { terms: { [filter.field]: filter.value } };
      case 'range':
        return { range: { [filter.field]: filter.value } };
      case 'exists':
        return { exists: { field: filter.field } };
      case 'bool':
        return { bool: filter.config };
      case 'geo_distance':
        return {
          geo_distance: {
            distance: filter.value.distance,
            [filter.field]: filter.value.location,
          },
        };
      case 'nested':
        return {
          nested: {
            path: filter.config.path,
            query: filter.config.query,
          },
        };
      default:
        return null;
    }
  }).filter(Boolean);
}

